function solve(n) {
    // Step 1: Reverse n to get r
    const s = String(n);
    const reversedS = s.split('').reverse().join('');
    const r = parseInt(reversedS);

    // Step 2: Determine the range
    const L = Math.min(n, r);
    const R = Math.max(n, r);

    // Helper function for primality test (optimized for small numbers)
    const isPrime = (k) => {
        if (k <= 1) return false;
        if (k <= 3) return true;
        if (k % 2 === 0 || k % 3 === 0) return false;

        let i = 5;
        while (i * i <= k) {
            if (k % i === 0 || k % (i + 2) === 0) return false;
            i += 6;
        }
        return true;
    };

    let sum = 0;

    // Step 3 & 4: Iterate from L to R and sum primes
    for (let i = L; i <= R; i++) {
        if (isPrime(i)) {
            sum += i;
        }
    }

    return sum;
}

